import React, { useState } from 'react';
import BookingSummary, { calcBookingTotal } from './BookingSummary';
import ConfirmationPage from './ConfirmationPage';
import styles from '../styles/BookingPage.module.css';

function generateRefCode() {
  return 'MZY-' + Math.random().toString(36).toUpperCase().slice(2, 8);
}

const BookingPage = () => {
  // Booking type: 'dayUse' | 'overnight' | null
  const [bookingType, setBookingType] = useState(null);
  const [checkIn, setCheckIn] = useState('');
  const [guests, setGuests] = useState(1);
  const [guestName, setGuestName] = useState('');
  const [guestContact, setGuestContact] = useState('');
  const [contactMethod, setContactMethod] = useState('email');
  const [specialRequests, setSpecialRequests] = useState('');
  const [confirmation, setConfirmation] = useState(null);

  const handleSubmit = () => {
    const { total } = calcBookingTotal(bookingType, checkIn, guests);
    setConfirmation({
      bookingType,
      checkIn,
      guests,
      guestName,
      guestContact,
      contactMethod,
      specialRequests,
      total,
      refCode: generateRefCode(),
    });
  };

  const handleNewBooking = () => {
    setBookingType(null);
    setCheckIn('');
    setGuests(1);
    setGuestName('');
    setGuestContact('');
    setContactMethod('email');
    setSpecialRequests('');
    setConfirmation(null);
  };

  if (confirmation) {
    return <ConfirmationPage data={confirmation} onNewBooking={handleNewBooking} />;
  }

  return (
    <div className={styles.page}>
      <div className={styles.layout}>
        {/* ── Left / Main form column ── */}
        <main className={styles.main}>
          <header className={styles.hero}>
            <span className={styles.kanji}>水屋</span>
            <h1 className={styles.heroTitle}>Mizuya Exclusive Resort</h1>
            <p className={styles.heroSub}>Soft Opening Rates</p>
          </header>

          {/* Step 1 – Choose booking type */}
          <section className={styles.section}>
            <h2 className={styles.sectionTitle}>1. Choose Your Stay</h2>
            <div className={styles.typeGrid}>
              <button
                type="button"
                className={`${styles.typeCard} ${bookingType === 'dayUse' ? styles.typeCardActive : ''}`}
                onClick={() => setBookingType('dayUse')}
              >
                <span className={styles.typeEmoji}>☀️</span>
                <span className={styles.typeName}>Day Use</span>
                <span className={styles.typeHours}>8:00 AM – 8:00 PM</span>
                <span className={styles.typeRate}>From ₱8,000</span>
              </button>
              <button
                type="button"
                className={`${styles.typeCard} ${bookingType === 'overnight' ? styles.typeCardActive : ''}`}
                onClick={() => setBookingType('overnight')}
              >
                <span className={styles.typeEmoji}>🌙</span>
                <span className={styles.typeName}>Overnight</span>
                <span className={styles.typeHours}>2:00 PM – 11:00 AM</span>
                <span className={styles.typeRate}>From ₱10,000</span>
              </button>
            </div>

            {bookingType && (
              <div className={styles.rateNote}>
                <span>Weekday (Mon–Thu)</span>
                <strong>
                  ₱{bookingType === 'dayUse' ? '8,000' : '10,000'}
                </strong>
                <span className={styles.rateSep}>·</span>
                <span>Weekend (Fri–Sun)</span>
                <strong>
                  ₱{bookingType === 'dayUse' ? '10,000' : '13,000'}
                </strong>
              </div>
            )}
          </section>

          {/* Step 2 – Date & Guests */}
          <section className={styles.section}>
            <h2 className={styles.sectionTitle}>2. Date &amp; Guests</h2>
            <div className={styles.fieldRow}>
              <label className={styles.fieldLabel} htmlFor="checkIn">
                Date
              </label>
              <input
                id="checkIn"
                type="date"
                className={styles.input}
                value={checkIn}
                min={new Date().toISOString().split('T')[0]}
                onChange={e => setCheckIn(e.target.value)}
              />
            </div>
            <div className={styles.fieldRow}>
              <label className={styles.fieldLabel} htmlFor="guests">
                Number of Guests
              </label>
              <input
                id="guests"
                type="number"
                className={styles.input}
                value={guests}
                min={1}
                max={30}
                onChange={e => setGuests(Number(e.target.value))}
              />
              <p className={styles.fieldNote}>
                Includes up to 15 guests · ₱250/extra guest (up to 15 extra)
              </p>
            </div>
          </section>

          {/* Step 3 – Guest Details */}
          <section className={styles.section}>
            <h2 className={styles.sectionTitle}>3. Your Details</h2>
            <div className={styles.fieldRow}>
              <label className={styles.fieldLabel} htmlFor="guestName">Full Name</label>
              <input
                id="guestName"
                type="text"
                className={styles.input}
                placeholder="e.g. Maria Santos"
                value={guestName}
                onChange={e => setGuestName(e.target.value)}
              />
            </div>
            <div className={styles.fieldRow}>
              <label className={styles.fieldLabel}>Contact via</label>
              <div className={styles.toggleRow}>
                <button
                  type="button"
                  className={`${styles.toggleBtn} ${contactMethod === 'email' ? styles.toggleActive : ''}`}
                  onClick={() => setContactMethod('email')}
                >
                  ✉ Email
                </button>
                <button
                  type="button"
                  className={`${styles.toggleBtn} ${contactMethod === 'messenger' ? styles.toggleActive : ''}`}
                  onClick={() => setContactMethod('messenger')}
                >
                  ✦ Messenger
                </button>
              </div>
            </div>
            <div className={styles.fieldRow}>
              <label className={styles.fieldLabel} htmlFor="guestContact">
                {contactMethod === 'email' ? 'Email Address' : 'Messenger Link or Username'}
              </label>
              <input
                id="guestContact"
                type={contactMethod === 'email' ? 'email' : 'text'}
                className={styles.input}
                placeholder={
                  contactMethod === 'email'
                    ? 'you@email.com'
                    : 'facebook.com/yourprofile'
                }
                value={guestContact}
                onChange={e => setGuestContact(e.target.value)}
              />
            </div>
            <div className={styles.fieldRow}>
              <label className={styles.fieldLabel} htmlFor="special">Special Requests</label>
              <textarea
                id="special"
                className={`${styles.input} ${styles.textarea}`}
                placeholder="Dietary needs, celebrations, accessibility requirements…"
                value={specialRequests}
                onChange={e => setSpecialRequests(e.target.value)}
                rows={3}
              />
            </div>
          </section>
        </main>

        {/* ── Right / Summary sidebar ── */}
        <BookingSummary
          bookingType={bookingType}
          checkIn={checkIn}
          guests={guests}
          guestName={guestName}
          guestContact={guestContact}
          contactMethod={contactMethod}
          onSubmit={handleSubmit}
        />
      </div>
    </div>
  );
};

export default BookingPage;
